export type playerBuffs = {
    size? :  number,
    zoom? :  number,
    speed? :  number,
    bulletSpeed? :  number,
    bulletSize? :  number,
    attackSpeed? :  number,
    exodias?: string,
}
export type Augment = {
    tag?: string,
    title: string,
    content?: string,
    buffs?: playerBuffs,
}
export const silverAugments : Array<Augment> = [
    {
        title: 'Size',
        buffs: {
            size: -2.5,
        }
    },
    {
        title: 'Zoom',
        buffs: {
            zoom: -0.05,
        }
    },
    {
        title: 'Speed',
        buffs: {
            speed: 50,
        }
    },
    {
        title: 'Bullet Speed',
        buffs: {
            bulletSpeed: 50,
        }
    },
    {
        title: 'Bullet Size',
        buffs: {
            bulletSize: 2.5,
        }
    },
    {
        title: 'Attack Speed',
        buffs: {
            attackSpeed: -0.05,
        }
    },
]
export const goldAugments: Array<Augment> = silverAugments.map(aug => ({
    ...aug,
    title: aug.title + '+',
    buffs: Object.fromEntries(
        Object.entries(aug.buffs || {}).map(([key, value]) => [
            key,
            (value as number) * 2
        ])
    )
}));
