import { insertCoin, isHost, myPlayer, PlayerState, getParticipants } from 'playroomkit';
import { Augment, exodiaAugments, goldAugments, playerBuffs, prismaticAugments, silverAugments } from './augments';
import { addUpgrades, capitalize, lerpAngle, outlinePlayerText, outlineText } from './helper';
import kaplay from 'kaplay';
import { DefaultStats, defaultStats} from './default';

await insertCoin();

export const k = kaplay({debugKey: '+', background:'white'});

const playerUpgrades = new Map<string, playerBuffs>();
const playerStats    = new Map<string, DefaultStats>();
k.setLayers(['bg', 'game', 'ui'], 'game')

k.scene('augments', () => {
    let clicked = false;
    
    function augmentButton(
        offestX = 0,
        type : 'silver' | 'gold' | 'prismatic' | 'exodia',
        augment: Augment,
    ) {
        if (type == 'exodia') {
            const btn = k.add([
                k.pos(k.width()/2+offestX, k.height()/2),
                k.area(),
                k.rect(400, 500),
                k.outline(5, k.Color.RED),
                k.color('black'),
                k.anchor('center'),
                'augment',
            ]);

            btn.add([
                k.pos(0, -100),
                k.text(augment.title, {align: 'center', width: 350}),
                k.anchor("center"),
                k.color('red'),
            ]);

            btn.add([
                k.pos(0, -30),
                k.text(augment.content, {align: 'center', width: 350}),
                k.anchor("top"),
                k.color('red'),
            ])

            btn.onClick(() => {
                if (clicked) return;
                clicked = true;

                k.destroyAll('augment');
                playerUpgrades.set(myPlayer().id, {
                    exodias: augment.tag
                });
                
                myPlayer().setState('upgrade', playerUpgrades.get(myPlayer().id));
            },'left');

            return btn;
        }else {
            const btn = k.add([
                k.pos(k.width()/2+offestX, k.height()/2),
                k.area(),
                k.rect(400, 500),
                k.outline(5),
                type != 'prismatic' ? k.color(type) : k.color(),
                k.anchor('center'),
                'augment',
            ]);

            btn.add([
                k.pos(0, -100),
                k.text(augment.title),
                k.anchor("center"),
                k.color(0, 0, 0),
            ]);

            let i = 0;
            for (const [key, value] of Object.entries(augment.buffs)) {
                btn.add([
                    k.pos(0, i),
                    k.text(`${capitalize(key)}: ${(value as number) > 0 ? '+' + value : value}`),
                    k.anchor("center"),
                    k.color(0, 0, 0),
                ])
                i += 50;
            }

            btn.onUpdate(() => {
                if (type == 'prismatic') btn.color = k.hsl2rgb(k.wave(0, 1, k.time()), 0.6, 0.6);
            });

            btn.onClick(() => {
                if (clicked) return;
                clicked = true;

                k.destroyAll('augment');
                const localStats = {};
                for (let key in augment.buffs) {
                    localStats[key] = augment.buffs[key];
                }
                playerUpgrades.set(myPlayer().id, localStats);
                
                myPlayer().setState('upgrade', playerUpgrades.get(myPlayer().id));
            },'left');

            return btn;
        }
    }

    const availableExodia     = [...exodiaAugments].filter(augment => playerStats.size == 0 || !playerStats.get(myPlayer().id).exodias.includes(augment.tag));
    const availablePrismatics = [...prismaticAugments];
    const availableGolds      = [...goldAugments];
    const availableSilvers    = [...silverAugments];
    for (let i = 0; i < 3; i++) {
        const exoidaRNG = k.randi(10);
        
        if (exoidaRNG == 0 && availableExodia.length > 0) {
            const index = k.randi(0, availableExodia.length);
            augmentButton(-450+i*450, 'exodia', availableExodia[index]);
            availableExodia.splice(index,1);
            continue;
        }

        const typeRNG = k.randi(30);

        // FUN MODE
        // EXODIA - 1/10  - 10%
        // PRISM  - 6/30  - 20%
        // GOLD   - 10/30 - 33%
        // SIVLER - 14/30 - 46%

        // EXODIA - 1/50  - 2%
        // PRISM  - 1/20  - 5%
        // GOLD   - 4/20  - 20%
        // SIVLER - 15/20 - 75%
        
        if (typeRNG <= 5) {
            const index = k.randi(0, availablePrismatics.length);
            augmentButton(-450+i*450, 'prismatic', availablePrismatics[index]);
            availablePrismatics.splice(index,1);
        }else if(typeRNG <= 15) {
            const index = k.randi(0, availableGolds.length);
            augmentButton(-450+i*450, 'gold', availableGolds[index]);
            availableGolds.splice(index,1);
        }else {
            const index = k.randi(0, availableSilvers.length);
            augmentButton(-450+i*450, 'silver', availableSilvers[index]);
            availableSilvers.splice(index,1);
        }
    }

    if (isHost()) {
        let once = true;
        k.onUpdate(() => {
            for (const serverPlayer of Object.values(getParticipants())) {
                if (serverPlayer.id == myPlayer().id) continue;
                if (playerUpgrades.has(serverPlayer.id)) continue;
                const upgrade = serverPlayer.getState('upgrade') || false;

                if (upgrade) {
                    playerUpgrades.set(serverPlayer.id, upgrade);
                    serverPlayer.setState('upgrade', null);
                    k.debug.log(`${serverPlayer.getProfile().name} READY`);
                }
            }

            if (playerUpgrades.size == Object.values(getParticipants()).length && once) {
                once = false;
                k.debug.log('SVI SU READY');
            
                let countdown = 3;
                const timer = k.loop(1, () => {
                    k.debug.log(`GAME IN ${countdown}`);
                    countdown--;
                    
                    if (countdown == 0) {
                        timer.cancel();
                    }
                });
                k.wait(countdown, () => {
                    for (const serverPlayer of Object.values(getParticipants())) {
                        if (serverPlayer.id == myPlayer().id) continue;
                        serverPlayer.setState('game', true);
                    }
                    k.go('game');
                });
            }
        });
    }else {
        k.onUpdate(() => {
            const isGameTime = myPlayer().getState('game') || false;

            if (isGameTime) {
                myPlayer().setState('game', false);
                k.go('game');
            }
        });
    }
});

k.scene('game', () => {
    const exodiasObj = new Map<string, any>();
    const mapSize = Object.keys(getParticipants()).length*500;
    let entitiyId = 0;

    addUpgrades(playerStats, playerUpgrades);
    [
        {
            x: 0,
            y: 0,
            w: mapSize,
            h: 5,
        },
        {
            x: mapSize-5,
            y: 0,
            w: 5,
            h: mapSize,
        },
        {
            x: 0,
            y: mapSize-5,
            w: mapSize,
            h: 5,
        },
        {
            x: 0,
            y: 0,
            w: 5,
            h: mapSize,
        },
    ].map(({x,y,w,h}) => {
        k.add([
            k.pos(x,y),
            k.color('black'),
            k.rect(w, h),
            k.area({ collisionIgnore: ['boundary'] }),
            k.body({ isStatic: true }),
            'boundary',
        ]);
    });

    function spawnPlayer(serverPlayer: PlayerState) {
        const stats = playerStats.get(serverPlayer.id) || structuredClone(defaultStats);

        const player = k.add([
            k.circle(stats.size),
            k.color(serverPlayer.getProfile().color.hexString),
            k.outline(5),
            k.anchor('center'),
            k.pos(0,0),
            k.z(3),
            k.health(10),
            k.area(),
            k.body(),
            {
                stats: stats,
                alive: true,
                freeze: false,
                invincible: false,
                online: {
                    color: serverPlayer.getProfile().color.hexString,
                    name: serverPlayer.getProfile().name,
                    id: serverPlayer.id,
                }
            },
            'player',
            serverPlayer.id,
        ]);
        if (myPlayer().id == serverPlayer.id) {
            player.tag('localPlayer');
            k.setCamScale(player.stats.zoom);
        }

        const healthBar = player.add([
            k.color('green'),
            k.rect(80, 10),
            k.pos(0, player.stats.size+10/2+10),
            k.opacity(1),
            k.anchor('center'),
            k.layer('ui'),
        ]);

        const guns = [];
        if (player.stats.exodias.includes('octo')) {
            for (let i = 0; i < 8; i++) {
                guns.push(player.add([
                    k.rotate(i*45),
                    k.anchor('bot'),
                    k.color('gray'),
                    k.rect(player.stats.bulletSize*2, player.stats.size*1.7),
                    k.outline(5),
                    k.z(2),
                ]));
            }
        }else {
            guns.push(
                player.add([
                    k.rotate(0),
                    k.anchor('bot'),
                    k.color('gray'),
                    k.rect(player.stats.bulletSize*2, player.stats.size*1.7),
                    k.outline(5),
                    k.z(2),
                ])
            );
        }
        
        if (player.is('localPlayer')) {
            for (let i = 0; i < player.stats.exodias.length; i++) {
                exodiasObj.set(player.stats.exodias[i], outlineText(capitalize(player.stats.exodias[i]), 5, 5+i*30));
            }
        }

        if (!player.is('localPlayer')) {
            outlinePlayerText(player);
        }

        if (isHost()) {
            player.moveTo(k.randi(5 + player.radius, mapSize - player.radius - 5), k.randi(5 + player.radius, mapSize - player.radius - 5));


            player.onHurt(() => {
                k.tween(k.RED, k.Color.fromHex(player.online.color), 0.15, (p) => player.color = p);
            });

            player.onDeath(() => {
                player.alive = false;
                serverPlayer.setState('player', {
                    alive: false,
                });

                k.get('domain').filter(e => e.is(serverPlayer.id)).forEach((domain, index) => {
                    for (const frozenPlayerId of domain.affected) {
                        const frozenPlayer = k.get(frozenPlayerId);
                        if (frozenPlayer.length == 0) continue;

                        frozenPlayer[0].freeze = false;
                    }
                    domain.countered = true;
                    domain.destroy();
                });

                player.destroy();

                if (k.get('player').length == 1) {
                    let countdown = 3;
                    k.debug.log('ROUND OVER');
                    const timer = k.loop(1, () => {
                        k.debug.log(`PICKING IN ${countdown}`);
                        countdown--;
                        
                        if (countdown == 0) {
                            timer.cancel();
                        }
                    });
                    k.wait(countdown, () => {
                        for (const serverPlayer of Object.values(getParticipants())) {
                            if (serverPlayer.id == myPlayer().id) continue;
                            serverPlayer.setState('augments', true);
                        }
                        k.go('augments');
                    });
                }
            });
        }

        player.onUpdate(() => {
            if (player.is('localPlayer')) {
                for (const exodia of player.stats.exodias) {
                    if (player[`${exodia}Active`]) {
                        exodiasObj.get(exodia).color = k.rgb(150, 150, 150);
                    }else {
                        exodiasObj.get(exodia).color = k.Color.WHITE;
                    }   
                }
            }

            if (player.is('localPlayer') && player.alive) {
                const dir = [];
                if (k.isKeyDown('a')) {
                    dir.push('left')
                }
                if (k.isKeyDown('d')) {
                    dir.push('right')
                }
                if (k.isKeyDown('w')) {
                    dir.push('up')
                }
                if (k.isKeyDown('s')) {
                    dir.push('down')
                }
                myPlayer().setState('dir', dir);

                k.tween(k.getCamPos(), player.pos, k.clamp(300/player.stats.speed,0,1), (p) => k.setCamPos(p), k.easings.easeOutExpo);

                const offset = k.getCamPos().sub(player.pos);
                myPlayer().setState('angle', k.mousePos().sub(k.center().sub(offset)).angle() + 90);

                const mouseInput = [];
                if (k.isMouseDown('left')) {
                    mouseInput.push('left')
                }
                if (k.isMouseDown('right')) {
                    mouseInput.push('right')
                }
                myPlayer().setState('mouse', mouseInput);
            }

            if (isHost()) {
                if (!k.get('player').some(e => e['sandevistanActive'])) {
                    k.debug.timeScale = 1;
                }

                const serverAngle = serverPlayer.getState('angle') || 0;
                if (k.get('player').some(e => e['sandevistanActive']) && !player['sandevistanActive']) {
                    if (player.stats.exodias.includes('octo')) {
                        for (let i = 0; i < guns.length; i++) {
                            guns[i].angle = lerpAngle(guns[i].angle, serverAngle+i*45, 0.10*k.debug.timeScale);
                        }
                    }else {
                        guns[0].angle = lerpAngle(guns[0].angle, serverAngle, 0.10*k.debug.timeScale);
                    }
                } else {
                    if (player.stats.exodias.includes('octo')) {
                        for (let i = 0; i < guns.length; i++) {
                            guns[i].angle = serverAngle+i*45; 
                        }
                    }else {
                        guns[0].angle = serverAngle;
                    }
                }

                if (!player.freeze) {
                    const dirs = {
                        'left': k.vec2(-1, 0),
                        'right': k.vec2(1, 0),
                        'up': k.vec2(0, -1),
                        'down': k.vec2(0, 1),
                    }

                    const serverDirs = serverPlayer.getState('dir') || [];
                    let dir = k.vec2(0, 0);
                    for (const serverDir of serverDirs) {
                        dir = dir.add(dirs[serverDir]);
                    }
                    player.move(dir.unit().scale(player.stats.speed));
                    player.moveTo(
                        k.clamp(player.pos.x, 5 + player.radius, mapSize - player.radius - 5),
                        k.clamp(player.pos.y, 5 + player.radius, mapSize - player.radius - 5)
                    );

                    const serverMouse = serverPlayer.getState('mouse') || [];
                    for (const mouse of serverMouse) {
                        if (mouse == 'left' && !player.stats.attackCooldown) {
                            player.stats.attackCooldown = true;

                            for (const gun of guns) {
                                const bullet = k.add([
                                    k.circle(player.stats.bulletSize),
                                    k.color(player.online.color),
                                    k.outline(5),
                                    k.pos(player.pos.add(k.Vec2.fromAngle(gun.angle - 90).scale(player.stats.size*1.7))),
                                    k.area({collisionIgnore: ['boundary', 'bullet', serverPlayer.id]}),
                                    k.opacity(),
                                    k.lifespan(2.5, {
                                        fade: 0.1,
                                    }),
                                    k.body(),
                                    k.move(gun.angle - 90, player.stats.bulletSpeed),
                                    k.z(1),
                                    'bullet',
                                    {
                                        bulletId: (entitiyId++),
                                        stats: {
                                            size: player.stats.bulletSize,
                                        },
                                        hitted: [],
                                    },
                                ]);

                                bullet.onBeforePhysicsResolve((col) => {
                                    if (col.target.is('player') && col.target.invincible) {
                                        col.preventResolution();
                                    }
                                });

                                bullet.onCollide('player', (hurtPlayer) => {
                                    if (bullet.hitted.some(p => p == hurtPlayer.online.id)) return;
                                    bullet.hitted.push(hurtPlayer.online.id);

                                    k.wait(0.05, () => {bullet.destroy()});
                                    if (!hurtPlayer.invincible) {
                                        hurtPlayer.hp--;
                                    }
                                });
                            }

                            k.wait(player.stats.attackSpeed, () => {player.stats.attackCooldown = false});
                        }else if (mouse == 'right' && player.stats.exodias.includes('domain') && !player['domainActive']) {
                            player['domainActive'] = true;
                            player.freeze = true;
                            player.invincible = true;

                            const domain = k.add([
                                k.anchor('center'),
                                k.pos(player.pos),
                                k.circle(20),
                                k.scale(),
                                k.color('red'),
                                k.area({isSensor: true, collisionIgnore: ['boundary', serverPlayer.id]}),
                                k.animate(),
                                'domain',
                                {
                                    countered: false,
                                    domainId: (entitiyId++),
                                    affected: [],
                                },
                                serverPlayer.id,
                            ]);
                            const speed = 3;
                            const domainController = k.tween(k.vec2(0), k.vec2(30), speed, (p) => domain.scale = p, k.easings.linear);
                            domain.onCollide('player', (hurtPlayer) => {
                                domain.affected.push(hurtPlayer.online.id)
                                if (!player.invincible || player.stats.exodias.includes('domain')) hurtPlayer.hp = 0;
                            });
                            domain.onCollide('bullet', (hurtBullet) => {
                                hurtBullet.destroy();
                            });
                            domainController.onEnd(async () => {
                                if (domain.countered) return;
                                await k.wait(0.5);

                                //10
                                k.wait(10, () => {
                                    player['domainActive'] = false;
                                });

                                domain.destroy();
                                player.freeze = false;
                                player.invincible = false;
                            });
                        }else if (mouse == 'right' && player.stats.exodias.includes('sandevistan') && !player['sandevistanActive']) {
                            player.hp -= 2;
                            if (player.hp == 0) continue;
                            player['sandevistanActive'] = true;

                            const slowTime = 5;
                            const sandBoost = 700;
                            
                            k.debug.timeScale = 1/slowTime;
                            player.stats.speed = player.stats.speed * slowTime + sandBoost;

                            k.wait(3*(1/slowTime), () => {
                                player.stats.speed = (player.stats.speed - sandBoost) / slowTime;
                                player['sandevistanActive'] = false;
                            });
                        }
                    }
                }

                if (player['sandevistanActive'] && !player['sandevistanTrail']) { 
                    player['sandevistanTrail'] = true;

                    const trailSpeed = 0.05;
                    const event = k.loop(trailSpeed*k.debug.timeScale, () => {
                        if (k.debug.timeScale == 1) return;
                        const ghost = k.add([
                            k.pos(player.pos.x, player.pos.y),
                            k.circle(player.stats.size),
                            k.outline(5),
                            k.anchor('center'),
                            k.color(k.rgb(255, 0, 60)),
                            k.opacity(0.6),
                            k.lifespan(1*k.debug.timeScale),
                            k.z(-1),
                            'sandevistan',
                            {
                                sandevistanId: (entitiyId++),
                            }
                        ]);
                        k.tween(ghost.color, k.rgb(0,200,255), 1*k.debug.timeScale, (p) => ghost.color = p, k.easings.linear);
                    }, 3/trailSpeed + 1);
                    event.onEnd(() => { 
                        player['sandevistanTrail'] = false; 
                    });
                }

                healthBar.width = player.hp*8;

                const exoidasActive = [];
                for (const exodia of player.stats.exodias) {
                    if (player[`${exodia}Active`]) {
                        exoidasActive.push(exodia);
                    }  
                }

                serverPlayer.setState('player', {
                    exodiasActive: exoidasActive,
                    exodias: player.stats.exodias,
                    color: player.color,
                    pos: player.pos,
                    size: player.stats.size,
                    bulletSize: player.stats.bulletSize,
                    hp: player.hp,
                    angle: guns[0].angle,
                    alive: player.alive,
                });
            } else {
                const isAugmentTime = myPlayer().getState('augments') || false;
                if (isAugmentTime) {
                    myPlayer().setState('augments', false);
                    k.go('augments');
                }

                const playerData = serverPlayer.getState('player') || 
                    { color: {r:255,g:255,b:255}, pos: { x: 0, y: 0 }, hp: 0, angle: 0, size: 0, bulletSize: 0, alive: true, exodias: [], exodiasActive: [] };
                
                player.alive = playerData.alive;
                if (!player.alive) {
                    player.hidden = true
                    return;
                } else {
                    player.hidden = false
                }
                player.moveTo(
                    k.lerp(player.pos.x, playerData.pos.x, 30*k.dt()),
                    k.lerp(player.pos.y, playerData.pos.y, 30*k.dt())
                );
                player.color = playerData.color;
                player.radius = playerData.size;
                for (const exodia of playerData.exodias) {
                    player[`${exodia}Active`] = false;
                }
                for (const exodia of playerData.exodiasActive) {
                    player[`${exodia}Active`] = true;
                }
                healthBar.width = playerData.hp*8;
                healthBar.pos.y = playerData.size+10/2+10;

                if (playerData.exodias.includes('octo') && guns.length != 8) {
                    for (let i = 1; i < 8; i++) {
                        guns.push(player.add([
                            k.rotate(i*45),
                            k.anchor('bot'),
                            k.color('gray'),
                            k.rect(player.stats.bulletSize*2, player.stats.size*1.7),
                            k.outline(5),
                            k.z(2),
                        ]));
                    }
                }

                for (let i = 0; i < guns.length; i++) {
                    guns[i].width = playerData.bulletSize*2;
                    guns[i].height = playerData.size*1.7;
                    guns[i].angle = playerData.angle + i*45;
                }
            }
        });

        serverPlayer.onQuit(() => k.destroy(player));
    }

    for (const serverPlayer of Object.values(getParticipants())) {
        spawnPlayer(serverPlayer);
    }

    k.onUpdate(() => {
        if (
            (isHost() && k.get('localPlayer').length == 0) ||
            (!isHost() && !k.get('localPlayer')[0].alive)
        ) {
            const cameraX = k.isKeyDown('a') ? -100 : k.isKeyDown('d') ? 100 : 0;
            const cameraY = k.isKeyDown('w') ? -100 : k.isKeyDown('s') ? 100 : 0;
            k.tween(k.getCamPos(), k.getCamPos().add(cameraX,cameraY), 1, (p) => k.setCamPos(p), k.easings.easeOutExpo);
        }

        if (isHost()) {
            myPlayer().setState('bullets', k.get('bullet').map(bullet => (
                {
                    bulletId: bullet.bulletId,
                    pos: bullet.pos,
                    bulletSize: bullet.stats.size,
                    opacity: bullet.opacity,
                    color: bullet.color,
                }
            )));
            myPlayer().setState('domains', k.get('domain').map(domain => (
                {
                    domainId: domain.domainId,
                    pos: domain.pos,
                    scale: domain.scale,
                }
            )));
            myPlayer().setState('sandevistans', k.get('sandevistan').map(sandevistan => (
                {
                    sandevistanId: sandevistan.sandevistanId,
                    pos: sandevistan.pos,
                    size: sandevistan.radius,
                    color: sandevistan.color,
                }
            )));
        } else {
            //SANDEVISTAN
            let sandevistansData = [];
            for (const serverPlayer of Object.values(getParticipants())) {
                sandevistansData = serverPlayer.getState('sandevistans') || [];
                if (sandevistansData.length > 0) break;
            }
            const sandevistans = k.get('sandevistan');

            for (const sandevistanData of sandevistansData) {
                const sandevistan = sandevistans.find(sandevistan => sandevistan.sandevistanId == sandevistanData.sandevistanId);
                if (sandevistan) {
                    sandevistan.color.r = k.lerp(sandevistan.color.r, sandevistanData.color.r, 30*k.dt());
                    sandevistan.color.g = k.lerp(sandevistan.color.g, sandevistanData.color.g, 30*k.dt());
                    sandevistan.color.b = k.lerp(sandevistan.color.b, sandevistanData.color.b, 30*k.dt());
                } else {
                    k.add([
                        k.pos(sandevistanData.pos.x, sandevistanData.pos.y),
                        k.circle(sandevistanData.size),
                        k.outline(5),
                        k.anchor('center'),
                        k.color(k.rgb(255, 0, 60)),
                        k.opacity(0.6),
                        k.z(-1),
                        'sandevistan',
                        {
                            sandevistanId: sandevistanData.sandevistanId,
                        }
                    ]);
                }
            }

            const removedSandevistans = sandevistans.filter(sandevistan => !sandevistansData.some(sandevistanData => sandevistanData.sandevistanId == sandevistan.sandevistanId));
            for (const removedSandevistan of removedSandevistans) {
                removedSandevistan.destroy();
            }

            //DOMAIN
            let domainsData = [];
            for (const serverPlayer of Object.values(getParticipants())) {
                domainsData = serverPlayer.getState('domains') || [];
                if (domainsData.length > 0) break;
            }
            const domains = k.get('domain');

            for (const domainData of domainsData) {
                const domain = domains.find(domain => domain.domainId == domainData.domainId);
                if (domain) {
                    domain.scaleTo(
                        k.lerp(domain.scale.x, domainData.scale.x, 30*k.dt()),
                        k.lerp(domain.scale.y, domainData.scale.y, 30*k.dt()),
                    );
                } else {
                    k.add([
                        k.anchor('center'),
                        k.pos(domainData.pos.x, domainData.pos.y),
                        k.circle(20),
                        k.scale(),
                        k.color('red'),
                        'domain',
                        {
                            domainId: domainData.domainId,
                        }
                    ]);
                }
            }

            const removedDomains = domains.filter(domain => !domainsData.some(domainData => domainData.domainId == domain.domainId));
            for (const removedDomain of removedDomains) {
                removedDomain.destroy();
            }
            
            //BULLET
            let bulletsData = [];
            for (const serverPlayer of Object.values(getParticipants())) {
                bulletsData = serverPlayer.getState('bullets') || [];
                if (bulletsData.length > 0) break;
            }
            const bullets = k.get('bullet');

            for (const bulletData of bulletsData) {
                const bullet = bullets.find(bullet => bullet.bulletId == bulletData.bulletId);
                if (bullet) {
                    bullet.moveTo(
                        k.lerp(bullet.pos.x, bulletData.pos.x, 30*k.dt()),
                        k.lerp(bullet.pos.y, bulletData.pos.y, 30*k.dt())
                    );
                    bullet.opacity = k.lerp(bullet.opacity, bulletData.opacity, 30*k.dt());
                } else {
                    k.add([
                        k.color(bulletData.color.r, bulletData.color.g, bulletData.color.b),
                        k.circle(bulletData.bulletSize),
                        k.outline(5),
                        k.pos(bulletData.pos.x, bulletData.pos.y),
                        k.opacity(),
                        k.z(1),
                        'bullet',
                        {
                            bulletId: bulletData.bulletId,
                        }
                    ]);
                }
            }

            const removedBullets = bullets.filter(bullet => !bulletsData.some(bulletData => bulletData.bulletId == bullet.bulletId));
            for (const removedBullet of removedBullets) {
                removedBullet.destroy();
            }
        }
    });

    playerUpgrades.clear();
});

k.go('game');